import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Objective & win/lose loop (MPG.1)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/objective-loop.md","filePath":"guide/objective-loop.md","lastUpdated":1781997265000}'),n={name:"guide/objective-loop.md"};function i(r,e,c,d,l,h){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="objective-win-lose-loop-mpg-1" tabindex="-1">Objective &amp; win/lose loop (MPG.1) <a class="header-anchor" href="#objective-win-lose-loop-mpg-1" aria-label="Permalink to &quot;Objective &amp; win/lose loop (MPG.1)&quot;">​</a></h1><p>The objective loop is what turns the forest sandbox into a <em>game</em>: a player who clicks <strong>New Game</strong> is given a goal — <strong>raid 3 caravans</strong> — surfaced on the HUD, and the run ends in an explicit <strong>win</strong> or <strong>lose</strong> screen with a <strong>Restart</strong> button. Score (kills + loot) is tracked throughout.</p><h2 id="the-run-flow" tabindex="-1">The run flow <a class="header-anchor" href="#the-run-flow" aria-label="Permalink to &quot;The run flow&quot;">​</a></h2><p>App/run flow is the <a href="./state-management"><code>appSlice</code></a> phase machine. MPG.1 adds two end-of-run phases:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>menu → playing ⇄ paused</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ├── objective complete ──▶ won  ──▶ (Restart → playing | Quit → menu)</span></span>
<span class="line"><span>          └── player HP reaches 0 ──▶ lost ──▶ (Restart → playing | Quit → menu)</span></span></code></pre></div><ul><li><code>winGame</code> / <code>loseGame</code> only transition <strong>from <code>playing</code></strong> — an already finished run never re-triggers, and a finished run cannot be paused.</li><li>On <code>won</code>/<code>lost</code> the live zone scene is <strong>unmounted</strong>: <code>GameCanvas</code> keeps a scene only while <code>playing</code>/<code>paused</code>, so the win/lose overlay sits above the menu engine scene. Restart bumps the run and boots a <strong>fresh</strong> zone scene from scratch (the capsule, raided caravans, and corpses all reset with it).</li></ul><h2 id="the-win-lose-state-machine" tabindex="-1">The win/lose state machine <a class="header-anchor" href="#the-win-lose-state-machine" aria-label="Permalink to &quot;The win/lose state machine&quot;">​</a></h2><p>The <em>decision</em> — given live progress, is the run still going, won, or lost? — is a pure function with no Redux/React/Babylon dependency, so it is exhaustively unit-testable:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/game/objective/objectiveMachine.ts</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evaluateOutcome</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ caravansRaided, target, playerDead }) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// → &#39;playing&#39; | &#39;won&#39; | &#39;lost&#39;</span></span></code></pre></div><p>Death takes priority over victory, keeping the function total. The App layer feeds it live state each frame (via the effects in <code>App.tsx</code>) and drives the <code>appSlice</code> phase from the result.</p><h2 id="objective-score-state" tabindex="-1">Objective &amp; score state <a class="header-anchor" href="#objective-score-state" aria-label="Permalink to &quot;Objective &amp; score state&quot;">​</a></h2><p>Per-run progress lives in <a href="./state-management"><code>gameSlice</code></a>:</p><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td><code>caravansRaided</code></td><td>Caravans raided this run — drives the win objective.</td></tr><tr><td><code>kills</code></td><td>Soldiers defeated this run.</td></tr><tr><td><code>objectiveTarget</code></td><td>Caravans required to win (<code>OBJECTIVE_CARAVAN_TARGET</code>, 3).</td></tr><tr><td><code>score</code></td><td>Running score shown in the HUD (see below).</td></tr></tbody></table><p><strong>Score</strong> accumulates as the run plays: <code>KILL_SCORE</code> (10) per soldier defeated plus the loot points (item count) of each caravan raided. The win condition is fed to <code>evaluateOutcome</code> from <code>App.tsx</code> (<code>caravansRaided &gt;= objectiveTarget</code>), not a selector — keeping the decision in the pure machine.</p><p>Actions: <code>recordKill</code>, <code>raidCaravan(lootPoints)</code>, <code>resetRun</code>. Both the New-Game flow (after the faction picker confirms a faction) and the win/lose <strong>Restart</strong> run the same full reset (<code>resetRun</code> + zone/HP/injuries/inventory) before entering play — Restart reuses the current faction rather than re-prompting. A continued save starts its objective fresh (objective progress is not yet persisted).</p><h2 id="how-progress-is-fed-from-the-scene" tabindex="-1">How progress is fed from the scene <a class="header-anchor" href="#how-progress-is-fed-from-the-scene" aria-label="Permalink to &quot;How progress is fed from the scene&quot;">​</a></h2><p>The forest scene stays decoupled from the store and reports events through callbacks that <code>GameCanvas</code> adapts into dispatches:</p><ul><li><strong>Caravan raided</strong> — defeating a caravan fires <code>onCaravanLooted(drop)</code> (see <a href="./caravans">caravans</a>). <code>GameCanvas</code> dispatches <code>pickUpLoot</code> per stack <strong>and</strong> <code>raidCaravan(totalItems)</code>, which advances the objective and folds the haul into the loot score. The forest ships a 3-caravan convoy so the objective is completable in the live build.</li><li><strong>Soldier killed</strong> — <code>reapDeadSoldiers</code> fires <code>onEnemyKilled</code> once per fresh death (see <a href="./enemy-ai">enemy AI</a> / <a href="./corpses">corpses</a>); <code>GameCanvas</code> dispatches <code>recordKill</code>.</li></ul><h2 id="hud" tabindex="-1">HUD <a class="header-anchor" href="#hud" aria-label="Permalink to &quot;HUD&quot;">​</a></h2><p>While playing/paused the HUD shows the objective counter (<code>Raid caravans — X / 3</code>) and the running <code>Score</code>. The win and lose screens reuse the menu/pause overlay chrome with win- and lose-tinted accents.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li><code>src/game/objective/objectiveMachine.test.ts</code> — the win/lose state machine, including the death-priority and zero-target edges.</li><li><code>src/store/gameSlice.test.ts</code> — objective/score reducers and selectors.</li><li><code>src/store/appSlice.test.ts</code> — <code>won</code>/<code>lost</code> transitions and guards.</li><li><code>src/app/App.test.tsx</code> — HUD objective/score, win and lose screens, and the end-to-end <strong>Restart from win → fresh game</strong> flow.</li></ul>`,22)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
